<!DOCTYPE html><html><head><meta charset='utf-8'><title>Datepicker</title><link rel='stylesheet' href='automation_playground.css'></head><body><div class='container'><a href='/index.php'>Home</a><h2>Datepicker</h2><div class='panel'><input id='datepicker-date' type='date'><input id='datepicker-time' type='time'><button id='datepicker-apply' class='btn'>Apply</button><input id='datepicker-result-iso' readonly></div></div><script>document.getElementById('datepicker-apply').onclick=()=>{const d=document.getElementById('datepicker-date').value;const t=document.getElementById('datepicker-time').value||'00:00';document.getElementById('datepicker-result-iso').value=d?`${d}T${t}:00Z`:''};</script></body></html>
